// POST /api/levels/:levelId/start - Get a challenge token before playing
app.post('/api/levels/:levelId/start', authenticateSession, (req, res) => {
  const levelId = parseInt(req.params.levelId);
  const user = users.get(req.userId);

  if (!user) return res.status(404).json({ error: 'User not found.' });
  if (user.banned) return res.status(403).json({ error: 'Account suspended.' });

  if (!LEVEL_CONFIG[levelId]) {
    return res.status(400).json({ error: 'Invalid level.' });
  }

  // Check level unlock progression (must complete previous level)
  if (levelId > 1 && !user.completedLevels[levelId - 1]) {
    return res.status(403).json({ error: 'Level not unlocked.' });
  }

  const challenge = generateChallenge(req.userId, levelId);

  // Store challenge server-side with start time
  const challengeKey = `${req.userId}:${levelId}`;
  const challengeRecord = {
    ...challenge,
    startTime: Date.now(),
    used: false,
  };

  // Store in session for verification later
  if (!req.session.activeChallenges) req.session.activeChallenges = {};
  req.session.activeChallenges[challengeKey] = challengeRecord;

  res.json({
    challengeToken: challenge.signature,
    levelId,
    nonce: challenge.nonce,
    timestamp: challenge.timestamp,
    config: {
      maxTime: LEVEL_CONFIG[levelId].maxTime,
    },
  });
});

// POST /api/levels/:levelId/complete - Submit level completion
app.post('/api/levels/:levelId/complete', completionLimiter, authenticateSession, (req, res) => {
  const levelId = parseInt(req.params.levelId);
  const user = users.get(req.userId);

  if (!user) return res.status(404).json({ error: 'User not found.' });
  if (user.banned) return res.status(403).json({ error: 'Account suspended.' });

  const {
    score,
    completionTime,
    moves,
    stars,
    challengeToken,
    nonce,
    challengeTimestamp,
    clientHash,
    inputEvents,
    moveSequence,
    deviceFingerprint,
  } = req.body;

  // Validate required fields
  if (score === undefined || completionTime === undefined || moves === undefined || !challengeToken || !nonce) {
    return res.status(400).json({ error: 'Missing required completion data.' });
  }

  // Verify challenge token
  const challengeKey = `${req.userId}:${levelId}`;
  const storedChallenge = req.session.activeChallenges?.[challengeKey];

  if (!storedChallenge) {
    return res.status(400).json({ error: 'No active challenge for this level. Start the level first.' });
  }

  if (storedChallenge.used) {
    return res.status(400).json({ error: 'Challenge already used. Start a new game.' });
  }

  // Verify challenge signature
  const challengeData = {
    userId: req.userId,
    levelId,
    timestamp: storedChallenge.timestamp,
    nonce: storedChallenge.nonce,
  };
  const expectedSig = generateHMAC(challengeData, CHALLENGE_SECRET);

  if (!crypto.timingSafeEqual(Buffer.from(challengeToken, 'hex'), Buffer.from(expectedSig, 'hex'))) {
    return res.status(400).json({ error: 'Invalid challenge token.' });
  }

  // Verify nonce matches
  if (nonce !== storedChallenge.nonce) {
    return res.status(400).json({ error: 'Nonce mismatch.' });
  }

  // Mark challenge as used
  storedChallenge.used = true;

  // Verify server-side elapsed time matches client-reported time
  const serverElapsedSeconds = (Date.now() - storedChallenge.startTime) / 1000;
  const timeDifference = Math.abs(serverElapsedSeconds - completionTime);

  // Allow some tolerance for network latency (5 seconds)
  if (timeDifference > 5 && completionTime < serverElapsedSeconds) {
    // Client claims faster time than server measured - suspicious
    return res.status(400).json({ error: 'Completion time mismatch with server records.' });
  }

  // Verify client hash (integrity check on the completion payload)
  if (clientHash) {
    const hashPayload = { score, completionTime, moves, levelId, nonce };
    const expectedHash = generateHMAC(hashPayload, SERVER_SECRET);
    try {
      if (!crypto.timingSafeEqual(Buffer.from(clientHash, 'hex'), Buffer.from(expectedHash, 'hex'))) {
        return res.status(400).json({ error: 'Data integrity check failed.' });
      }
    } catch (e) {
      return res.status(400).json({ error: 'Invalid client hash format.' });
    }
  }

  // Validate completion data against level constraints
  const validation = validateCompletionData(levelId, { score, completionTime, moves });
  if (!validation.valid) {
    return res.status(400).json({ error: validation.reason });
  }

  // Bot detection analysis
  const behaviorAnalysis = analyzeBehavior(req.userId, {
    levelId,
    score,
    completionTime,
    moves,
    inputEvents,
    moveSequence,
    deviceFingerprint,
  });

  if (behaviorAnalysis.isSuspicious) {
    user.suspicionLevel = (user.suspicionLevel || 0) + behaviorAnalysis.suspicionScore;

    // If accumulated suspicion is very high, ban the user
    if (user.suspicionLevel >= 200) {
      user.banned = true;
      sessions.delete(req.sessionToken);
      return res.status(403).json({ error: 'Account suspended for suspicious activity.' });
    }

    // For moderate suspicion, silently reduce rewards (shadow penalty)
    // Don't tell the client they're flagged
  }

  // Calculate server-authoritative reward
  const reward = calculateReward(levelId, score, serverElapsedSeconds, moves, stars);
  if (!reward) {
    return res.status(500).json({ error: 'Failed to calculate reward.' });
  }

  // Apply shadow penalty for suspicious users (reduce rewards without telling them)
  let appliedReward = { ...reward };
  if (user.suspicionLevel > 50) {
    const penaltyFactor = Math.max(0.1, 1 - (user.suspicionLevel / 300));
    appliedReward.coins = Math.floor(appliedReward.coins * penaltyFactor);
    appliedReward.gems = Math.floor(appliedReward.gems * penaltyFactor);
    appliedReward.xp = Math.floor(appliedReward.xp * penaltyFactor);
  }

  // Generate completion ID
  const completionId = crypto.randomUUID();

  // Store completion record
  const completionRecord = {
    completionId,
    userId: req.userId,
    levelId,
    score,
    completionTime,
    serverElapsedTime: serverElapsedSeconds,
    moves,
    stars: reward.stars,
    reward: appliedReward,
    rewardClaimed: false,
    behaviorFlags: behaviorAnalysis.flags,
    suspicionScore: behaviorAnalysis.suspicionScore,
    timestamp: Date.now(),
  };

  levelCompletions.set(completionId, completionRecord);

  // Update user's best completion for this level
  const existingBest = user.completedLevels[levelId];
  if (!existingBest || score > existingBest.score) {
    user.completedLevels[levelId] = {
      bestScore: score,
      bestStars: reward.stars,
      completionId,
    };
  }

  // Clean up used challenge
  delete req.session.activeChallenges[challengeKey];

  res.json({
    completionId,
    levelId,
    score,
    stars: reward.stars,
    reward: {
      coins: appliedReward.coins,
      gems: appliedReward.gems,
      xp: appliedReward.xp,
    },
    rewardClaimed: false,
  });
});

// POST /api/rewards/claim/:completionId - Claim reward for a completed level
app.post('/api/rewards/claim/:completionId', claimLimiter, authenticateSession, (req, res) => {
  const { completionId } = req.params;
  const user = users.get(req.userId);

  if (!user) return res.status(404).json({ error: 'User not found.' });
  if (user.banned) return res.status(403).json({ error: 'Account suspended.' });

  const completion = levelCompletions.get(completionId);
  if (!completion) {
    return res.status(404).json({ error: 'Completion record not found.' });
  }

  if (completion.userId !== req.userId) {
    return res.status(403).json({ error: 'This completion does not belong to you.' });
  }

  if (completion.rewardClaimed) {
    return res.status(400).json({ error: 'Reward already claimed.' });
  }

  // Check for duplicate claim attempts (idempotency)
  const claimKey = `${req.userId}:${completionId}`;
  if (claimedRewards.has(claimKey)) {
    return res.status(400).json({ error: 'Reward already claimed.' });
  }

  // Check completion age (rewards expire after 24 hours)
  if (Date.now() - completion.timestamp > 24 * 60 * 60 * 1000) {
    return res.status(400).json({ error: 'Reward has expired.' });
  }

  // Apply reward to user account
  const reward = completion.reward;
  user.coins += reward.coins;
  user.gems += reward.gems;
  user.xp += reward.xp;

  // Mark as claimed
  completion.rewardClaimed = true;
  claimedRewards.set(claimKey, {
    completionId,
    reward,
    claimedAt: Date.now(),
  });

  res.json({
    success: true,
    reward: {
      coins: reward.coins,
      gems: reward.gems,
      xp: reward.xp,
      stars: completion.stars,
    },
    updatedBalance: {
      coins: user.coins,
      gems: user.gems,
      xp: user.xp,
    },
  });
});

// GET /api/user/profile - Get user profile and balances
app.get('/api/user/profile', authenticateSession, (req, res) => {
  const user = users.get(req.userId);
  if (!user) return res.status(404).json({ error: 'User not found.' });

  res.json({
    userId: user.userId,
    username: user.username,
    coins: user.coins,
    gems: user.gems,
    xp: user.xp,
    completedLevels: Object.keys(user.completedLevels).reduce((acc, lvl) => {
      acc[lvl] = {
        bestScore: user.completedLevels[lvl].bestScore,
        bestStars: user.completedLevels[lvl].bestStars,
      };
      return acc;
    }, {}),
  });
});

// GET /api/levels - Get available levels
app.get('/api/levels', authenticateSession, (req, res) => {
  const user = users.get(req.userId);
  if (!user) return res.status(404).json({ error: 'User not found.' });

  const levels = Object.entries(LEVEL_CONFIG).map(([id, config]) => {
    const levelId = parseInt(id);
    const isUnlocked = levelId === 1 || !!user.completedLevels[levelId - 1];
    const completion = user.completedLevels[levelId];

    return {
      levelId,
      unlocked: isUnlocked,
      maxScore: config.maxScore,
      starThresholds: config.starThresholds,
      bestScore: completion?.bestScore || null,
      bestStars: completion?.bestStars || null,
    };
  });

  res.json({ levels });
});

// GET /api/rewards/pending - Get unclaimed rewards
app.get('/api/rewards/pending', authenticateSession, (req, res) => {
  const pendingRewards = [];

  for (const [id, completion] of levelCompletions) {
    if (completion.userId === req.userId && !completion.rewardClaimed) {
      // Check if not expired
      if (Date.now() - completion.timestamp <= 24 * 60 * 60 * 1000) {
        pendingRewards.push({
          completionId: completion.completionId,
          levelId: completion.levelId,
          score: completion.score,
          stars: completion.stars,
          reward: completion.reward,
          completedAt: completion.timestamp,
          expiresAt: completion.timestamp + 24 * 60 * 60 * 1000,
        });
      }
    }
  }

  res.json({ pendingRewards });
});

