// In production, this would be baked into the client binary, not served via API
app.get('/api/client/config', authenticateSession, (req, res) => {
  // Return a session-specific signing key derived from the server secret
  const sessionKey = crypto.createHmac('sha256', SERVER_SECRET)
    .update(req.sessionToken)
    .digest('hex');

  res.json({
    signingKey: sessionKey,
    version: '1.0.0',
  });
});

